  stimulus_type = NULL,
  options = '[{"id":"A","text":"The author’s use of rhetorical devices helps to create a sense of urgency and importance.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The author’s use of rhetorical devices helps to create a sense of humor and lightheartedness.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The author’s use of rhetorical devices helps to create a sense of confusion and uncertainty.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The author’s use of rhetorical devices helps to create a sense of boredom and indifference.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The author''s use of rhetorical devices, including vivid imagery, strong language, and emotional appeals, helps to create a sense of urgency and importance.  This, in turn, helps to convince the reader that the issue is important. The passage states that "The author of the text is trying to convince the reader that a particular issue is important. The author does this by us…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: The author’s use of rhetorical devices helps to create a sense of urgency and importance.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
